#include <iostream>
#include <string>
#include <string_view>

void printInfo(std::string_view sv) {
    std::cout << "Length: " << sv.length() << '\n';
    std::cout << sv << '\n';
}

int main() {
    std::string word{};
    std::cin >> word;
    printInfo(word);
    return 0;
}

