solution_code:
#include <iostream>
#include <string>
#include <string_view>

std::string_view firstWord(std::string_view sentence) {
    std::size_t pos{ sentence.find(' ') };
    if (pos == std::string_view::npos)
        return sentence;
    return sentence.substr(0, pos);
}

int main() {
    std::string line{};
    std::getline(std::cin, line);
    std::string_view sv{ line };
    std::cout << firstWord(sv) << '\n';
    return 0;
}
